  1	import * as React from 'react';
  2	import { ApprovalTaskKind, PipelineRunKind } from '../../types';
  3	import EllipsisVIcon from '@patternfly/react-icons/dist/esm/icons/ellipsis-v-icon';
  4	import {
  5	  Dropdown,
  6	  DropdownItem,
  7	  DropdownList,
  8	  MenuToggle,
  9	  MenuToggleElement,
 10	  Spinner,
 11	  Tooltip,
 12	} from '@patternfly/react-core';
 13	import { KEBAB_BUTTON_ID } from '../../consts';
 14	import { useTranslation } from 'react-i18next';
 15	import {
 16	  useAccessReview,
 17	  useModal,
 18	} from '@openshift-console/dynamic-plugin-sdk';
 19	import { ApprovalTaskModel } from '../../models';
 20	import { approvalModal } from './modal';
 21	import { ApproverStatusResponse } from '../../types';
 22	import { useActiveUserWithUpdate } from '../hooks/hooks';
 23	import { isUserAuthorizedForApproval } from '../utils/approval-group-utils';
 24	
 25	type ApprovalTaskActionDropdownProps = {
 26	  approvalTask: ApprovalTaskKind;
 27	  pipelineRun: PipelineRunKind;
 28	};
 29	
 30	const ApprovalTaskActionDropdown: React.FC<ApprovalTaskActionDropdownProps> = ({
 31	  approvalTask,
 32	  pipelineRun,
 33	}) => {
 34	  const { currentUser, updateUserInfo } = useActiveUserWithUpdate();
 35	  const launchModal = useModal();
 36	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 37	  const {
 38	    metadata: { name, namespace },
 39	    status: { state },
 40	    spec: { approvers },
 41	  } = approvalTask;
 42	  const [isOpen, setIsOpen] = React.useState(false);
 43	  const [isAuthorized, setIsAuthorized] = React.useState<boolean | null>(null);
 44	  const onToggle = () => {
 45	    setIsOpen(!isOpen);
 46	  };
 47	  const onSelect = () => {
 48	    setIsOpen(false);
 49	  };
 50	  const approveAction = () => {
 51	    launchModal(approvalModal, {
 52	      resource: approvalTask,
 53	      pipelineRunName: pipelineRun?.metadata?.name,
 54	      userName: currentUser?.username,
 55	      currentUser: currentUser,
 56	      type: 'approve',
 57	    });
 58	  };
 59	
 60	  const rejectAction = () => {
 61	    launchModal(approvalModal, {
 62	      resource: approvalTask,
 63	      pipelineRunName: pipelineRun?.metadata?.name,
 64	      userName: currentUser?.username,
 65	      currentUser: currentUser,
 66	      type: 'reject',
 67	    });
 68	  };
 69	
 70	  const canApproveAndRejectResource = useAccessReview({
 71	    group: ApprovalTaskModel.apiGroup,
 72	    resource: ApprovalTaskModel.plural,
 73	    verb: 'patch',
 74	    name,
 75	    namespace,
 76	  });
 77	
 78	  // Check group-based authorization
 79	  React.useEffect(() => {
 80	    const checkAuthorization = async () => {
 81	      if (currentUser && approvers) {
 82	        try {
 83	          if (currentUser?.username) {
 84	            const authorized = await isUserAuthorizedForApproval(
 85	              currentUser.username,
 86	              approvers,
 87	              currentUser,
 88	              updateUserInfo,
 89	            );
 90	            setIsAuthorized(authorized);
 91	          }
 92	        } catch (error) {
 93	          console.error('Error checking group authorization:', error);
 94	          setIsAuthorized(false);
 95	        }
 96	      } else {
 97	        setIsAuthorized(false);
 98	      }
 99	    };
100	    checkAuthorization();
101	  }, [currentUser, approvers]);
102	
103	  const isDropdownDisabled =
104	    !canApproveAndRejectResource ||
105	    state !== ApproverStatusResponse.Pending ||
106	    isAuthorized === null || // Still loading
107	    !isAuthorized; // Not authorized (includes both direct user and group checks)
108	
109	  const tooltipContent = () => {
110	    if (!canApproveAndRejectResource) {
111	      return t('Insufficient permissions');
112	    }
113	    if (state === ApproverStatusResponse.Timedout) {
114	      return t('PipelineRun has timed out');
115	    }
116	    if (state !== ApproverStatusResponse.Pending) {
117	      return t(`PipelineRun has been {{state}}`, { state });
118	    }
119	    if (isAuthorized === null) {
120	      return (
121	        (
122	          <Spinner
123	            className="pf-v6-u-mr-xs"
124	            size="sm"
125	            aria-label={t('Checking authorization...')}
126	          />
127	        ) + t('Checking authorization...')
128	      );
129	    }
130	    if (!isAuthorized) {
131	      return t('User not an approver');
132	    }
133	    return t('Permission denied');
134	  };
135	
136	  const dropdownItems = [
137	    <DropdownItem
138	      key="approve"
139	      component="button"
140	      isDisabled={isDropdownDisabled}
141	      data-test-action="approve-pipelineRun"
142	      onClick={approveAction}
143	    >
144	      {t('Approve')}
145	    </DropdownItem>,
146	    <DropdownItem
147	      key="reject"
148	      component="button"
149	      isDisabled={isDropdownDisabled}
150	      data-test-action="reject-pipelineRun"
151	      onClick={rejectAction}
152	    >
153	      {t('Reject')}
154	    </DropdownItem>,
155	  ];
156	
157	  return isDropdownDisabled ? (
158	    <Tooltip content={tooltipContent()} position="left">
159	      <Dropdown
160	        onSelect={onSelect}
161	        onOpenChange={(isOpen: boolean) => setIsOpen(isOpen)}
162	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
163	          <MenuToggle
164	            ref={toggleRef}
165	            aria-label="kebab menu"
166	            variant="plain"
167	            onClick={onToggle}
168	            isExpanded={isOpen}
169	            id={KEBAB_BUTTON_ID}
170	            data-test={KEBAB_BUTTON_ID}
171	          >
172	            <EllipsisVIcon />
173	          </MenuToggle>
174	        )}
175	        isOpen={isOpen && !isDropdownDisabled}
176	        isPlain={false}
177	        popperProps={{ position: 'right' }}
178	      >
179	        <DropdownList>{dropdownItems}</DropdownList>
180	      </Dropdown>
181	    </Tooltip>
182	  ) : (
183	    <Dropdown
184	      onSelect={onSelect}
185	      onOpenChange={(isOpen: boolean) => setIsOpen(isOpen)}
186	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
187	        <MenuToggle
188	          ref={toggleRef}
189	          aria-label="kebab menu"
190	          variant="plain"
191	          onClick={onToggle}
192	          isExpanded={isOpen}
193	          id={KEBAB_BUTTON_ID}
194	          data-test={KEBAB_BUTTON_ID}
195	        >
196	          <EllipsisVIcon />
197	        </MenuToggle>
198	      )}
199	      isOpen={isOpen}
200	      isPlain={false}
201	      popperProps={{ position: 'right' }}
202	    >
203	      <DropdownList>{dropdownItems}</DropdownList>
204	    </Dropdown>
205	  );
206	};
207	
208	export default ApprovalTaskActionDropdown;

